let mocha = require('mocha');
let assert = require('assert');
let quill_delta = require('quill-delta');

describe('test quill_delta', function() {
    it('should create empty delta when no ops provided', function(done) {
        let delta = new quill_delta();
        assert.deepEqual(delta.ops, []);
        done();
    });

    it('should create delta with ops array', function(done) {
        let ops = [{ insert: 'hello' }, { insert: ' world' }];
        let delta = new quill_delta(ops);
        assert.deepEqual(delta.ops, ops);
        done();
    });

    it('should create delta from another delta object', function(done) {
        let ops = [{ insert: 'test' }];
        let originalDelta = new quill_delta(ops);
        let newDelta = new quill_delta(originalDelta);
        assert.deepEqual(newDelta.ops, ops);
        done();
    });

    it('should insert text without attributes', function(done) {
        let delta = new quill_delta();
        delta.insert('hello');
        assert.deepEqual(delta.ops, [{ insert: 'hello' }]);
        done();
    });

    it('should insert text with attributes', function(done) {
        let delta = new quill_delta();
        delta.insert('hello', { bold: true });
        assert.deepEqual(delta.ops, [{ insert: 'hello', attributes: { bold: true } }]);
        done();
    });

    it('should not insert empty string', function(done) {
        let delta = new quill_delta();
        delta.insert('');
        assert.deepEqual(delta.ops, []);
        done();
    });

    it('should delete specified length', function(done) {
        let delta = new quill_delta();
        delta.delete(5);
        assert.deepEqual(delta.ops, [{ delete: 5 }]);
        done();
    });

    it('should not delete zero or negative length', function(done) {
        let delta = new quill_delta();
        delta.delete(0);
        delta.delete(-1);
        assert.deepEqual(delta.ops, []);
        done();
    });

    it('should retain specified length', function(done) {
        let delta = new quill_delta();
        delta.retain(5);
        assert.deepEqual(delta.ops, [{ retain: 5 }]);
        done();
    });

    it('should retain with attributes', function(done) {
        let delta = new quill_delta();
        delta.retain(5, { bold: true });
        assert.deepEqual(delta.ops, [{ retain: 5, attributes: { bold: true } }]);
        done();
    });

    it('should not retain zero or negative length', function(done) {
        let delta = new quill_delta();
        delta.retain(0);
        delta.retain(-1);
        assert.deepEqual(delta.ops, []);
        done();
    });

    it('should merge consecutive delete operations', function(done) {
        let delta = new quill_delta();
        delta.delete(3);
        delta.delete(2);
        assert.deepEqual(delta.ops, [{ delete: 5 }]);
        done();
    });

    it('should merge consecutive insert operations with same attributes', function(done) {
        let delta = new quill_delta();
        delta.insert('hello');
        delta.insert(' world');
        assert.deepEqual(delta.ops, [{ insert: 'hello world' }]);
        done();
    });

    it('should merge consecutive retain operations with same attributes', function(done) {
        let delta = new quill_delta();
        delta.retain(3);
        delta.retain(2);
        assert.deepEqual(delta.ops, [{ retain: 5 }]);
        done();
    });

    it('should chop trailing retain without attributes', function(done) {
        let delta = new quill_delta();
        delta.insert('hello');
        delta.retain(5);
        delta.chop();
        assert.deepEqual(delta.ops, [{ insert: 'hello' }]);
        done();
    });

    it('should not chop retain with attributes', function(done) {
        let delta = new quill_delta();
        delta.insert('hello');
        delta.retain(5, { bold: true });
        delta.chop();
        assert.deepEqual(delta.ops, [{ insert: 'hello' }, { retain: 5, attributes: { bold: true } }]);
        done();
    });

    it('should filter operations', function(done) {
        let delta = new quill_delta([
            { insert: 'hello' },
            { delete: 3 },
            { retain: 5 }
        ]);
        let filtered = delta.filter(op => op.insert);
        assert.deepEqual(filtered, [{ insert: 'hello' }]);
        done();
    });

    it('should map operations', function(done) {
        let delta = new quill_delta([
            { insert: 'hello' },
            { insert: 'world' }
        ]);
        let mapped = delta.map(op => op.insert);
        assert.deepEqual(mapped, ['hello', 'world']);
        done();
    });

    it('should calculate change length', function(done) {
        let delta = new quill_delta([
            { insert: 'hello' },  // +5
            { delete: 3 },        // -3
            { retain: 2 }         // +0
        ]);
        assert.equal(delta.changeLength(), 2);
        done();
    });

    it('should calculate total length', function(done) {
        let delta = new quill_delta([
            { insert: 'hello' },  // 5
            { delete: 3 },        // 3
            { retain: 2 }         // 2
        ]);
        assert.equal(delta.length(), 10);
        done();
    });
});
