        let emptyIterator = new quill_delta.OpIterator([]);
        assert.strictEqual(emptyIterator.hasNext(), false);

        // Test with single operation
        let singleOp = [{ insert: 'Hello' }];
        let singleIterator = new quill_delta.OpIterator(singleOp);
        assert.strictEqual(singleIterator.hasNext(), true);

        done();
    });

    it('test quill-delta.OpIterator next() method', function(done) {
        let ops = [
            { insert: 'Hello' },
            { insert: ' ' },
            { insert: 'World', attributes: { bold: true } }
        ];
        let iterator = new quill_delta.OpIterator(ops);

        // Test first operation
        assert.strictEqual(iterator.hasNext(), true);
        let firstOp = iterator.next();
        assert.deepStrictEqual(firstOp, { insert: 'Hello' });

        // Test second operation
        assert.strictEqual(iterator.hasNext(), true);
        let secondOp = iterator.next();
        assert.deepStrictEqual(secondOp, { insert: ' ' });

        // Test third operation
        assert.strictEqual(iterator.hasNext(), true);
        let thirdOp = iterator.next();
        assert.deepStrictEqual(thirdOp, { insert: 'World', attributes: { bold: true } });

        // Test end of iteration
        assert.strictEqual(iterator.hasNext(), false);

        done();
    });

    it('test quill-delta.OpIterator peek() method', function(done) {
        let ops = [
            { insert: 'Test' },
            { retain: 5 },
            { delete: 3 }
        ];
        let iterator = new quill_delta.OpIterator(ops);

        // Peek should return the next operation without advancing
        let peeked = iterator.peek();
        assert.deepStrictEqual(peeked, { insert: 'Test' });

        // hasNext should still be true
        assert.strictEqual(iterator.hasNext(), true);

        // next() should return the same operation
        let next = iterator.next();
        assert.deepStrictEqual(next, { insert: 'Test' });

        done();
    });

    it('test quill-delta.OpIterator with different operation types', function(done) {
        let ops = [
            { insert: 'Hello' },
            { retain: 10 },
            { delete: 5 },
            { insert: '\n', attributes: { header: 1 } }
        ];
        let iterator = new quill_delta.OpIterator(ops);

        // Test insert operation
        let insertOp = iterator.next();
        assert.strictEqual(insertOp.insert, 'Hello');

        // Test retain operation
        let retainOp = iterator.next();
        assert.strictEqual(retainOp.retain, 10);

        // Test delete operation
        let deleteOp = iterator.next();
        assert.strictEqual(deleteOp.delete, 5);

        // Test insert with attributes
